+use super::Stream;
+use std::pin::Pin;
+use std::task::{Context, Poll};
+
+/// Stream for the [`take`](super::StreamExt::take) method.
+#[derive(Debug)]
+#[must_use = "streams do nothing unless polled"]
+pub struct Take<S> {
+    stream: S,
+    remaining: usize,
+}
+
+impl<S> Take<S> {
+    pub(crate) fn new(stream: S, remaining: usize) -> Self {
+        Self { stream, remaining }
+    }
+}
+
+impl<S: Stream + Unpin> Stream for Take<S> {
+    type Item = S::Item;
+
+    fn poll_next(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Option<Self::Item>> {
+        if self.remaining == 0 {
+            return Poll::Ready(None);
+        }
+
+        let next = Pin::new(&mut self.stream).poll_next(cx);
+        match next {
+            Poll::Ready(Some(item)) => {
+                self.remaining -= 1;
+                Poll::Ready(Some(item))
+            }
+            Poll::Ready(None) => {
+                self.remaining = 0;
+                Poll::Ready(None)
+            }
+            Poll::Pending => Poll::Pending,
+        }
+    }
+
+    fn size_hint(&self) -> (usize, Option<usize>) {
+        if self.remaining == 0 {
+            return (0, Some(0));
+        }
+
+        let (lower, upper) = self.stream.size_hint();
+        let lower = lower.min(self.remaining);
+        let upper = match upper {
+            Some(x) => Some(x.min(self.remaining)),
+            None => Some(self.remaining),
+        };
+
+        (lower, upper)
+    }
+}
